INSERT INTO tools (name, name_en, category, description, description_en, price, rating, official_url, features, is_recommended, is_hot, is_new, slug, short_tag, full_desc, highlights, drawbacks, tg_advice, tags, sort_order, status) VALUES
('Linear AI', 'Linear AI', '程序员', '现代项目管理工具Linear内置AI功能，自动生成Issue描述、总结进度和预测完成时间。', 'Modern project management tool Linear with AI for issue generation and progress summaries.', '$8/用户/月', 4.6, 'https://linear.app', ARRAY['Issue AI自动生成','进度智能总结','完成时间预测','代码关联追踪'], false, true, false, 'linear-ai', 'AI项目', 'Linear内置AI项目管理工具', ARRAY['界面设计最优雅','AI功能实用','开发者体验好'], ARRAY['功能相对简单','高级功能需付费'], '开发团队项目管理的现代化工具', ARRAY['热门'], 2700, 'active');
INSERT INTO tools (name, name_en, category, description, description_en, price, rating, official_url, features, is_recommended, is_hot, is_new, slug, short_tag, full_desc, highlights, drawbacks, tg_advice, tags, sort_order, status) VALUES
('SonarQube AI', 'SonarQube AI', '程序员', '代码质量和安全分析平台，AI辅助检测代码异味、漏洞和技术债务，支持30+编程语言。', 'Code quality and security platform with AI detecting code smells, vulnerabilities and tech debt.', '免费+付费', 4.5, 'https://www.sonarsource.com', ARRAY['代码质量AI分析','安全漏洞检测','技术债务追踪','CI/CD流水线集成'], false, false, false, 'sonarqube-ai', '代码质量', 'AI代码质量安全分析30+语言', ARRAY['代码质量分析深','安全检测全面','CI集成方便'], ARRAY['配置较复杂','企业版价格高'], '团队代码质量管控的行业标准工具', ARRAY['热门'], 2600, 'active');
